import json
import inspect
from typing import Dict, Any, Callable


# To collect definitions
class WorkflowRegistry:
    def __init__(self):
        self.agents = {}
        self.workflows = {}


registry = WorkflowRegistry()


class AgentDef:
    def __init__(self, name: str, agent_type: str, func: Callable):
        self.name = name
        self.agent_type = agent_type
        self.func = func


def defn(type: str = "generic"):
    def wrapper(func):
        name = func.__name__
        registry.agents[name] = AgentDef(name, type, func)
        return func

    return wrapper


class agent:
    defn = defn


class WorkflowDef:
    def __init__(self, name: str, cls: type):
        self.name = name
        self.cls = cls
        self.run_method = None

        for attr_name in dir(cls):
            attr = getattr(cls, attr_name)
            if hasattr(attr, "_is_workflow_run"):
                self.run_method = attr
                break


class workflow:
    @staticmethod
    def defn(name: str):
        def wrapper(cls):
            registry.workflows[name] = WorkflowDef(name, cls)
            return cls

        return wrapper

    @staticmethod
    def run(func):
        func._is_workflow_run = True
        return func
